//   pmpcfg_base_t cfg0;
// } pmpcfg_t;

typedef pmpcfg_base_t [3:0] pmpcfg_t;

typedef logic [31:0] pmpaddr_t;

endpackage

`endif //PMP_TYPES_1_12_PKG_SV

